function _formatOCRData(ocrData) {

  let formattedOCRData = {};
  let predictionData = ocrData.map(elem => elem.prediction);
  predictionData = predictionData.flat(1);
  //remove undefined elements
  predictionData = predictionData.filter(elem => {
    return elem !== undefined;
  });
  predictionData.forEach(elem => {
    if ((formattedOCRData[elem.label] && formattedOCRData[elem.label]['score'] < elem.score) ||
      !formattedOCRData[elem.label]) {
      formattedOCRData[elem.label] = { 'value': elem.ocr_text, 'score': elem.score };
    }
  });

  return formattedOCRData;
}

