const _nextGreaterOrEqualElement = function (day, array) {
  let low = 0,
    high = array.length - 1;

  while (high - low > 0) {
    let mid = parseInt((low + high) / 2, 10);
    if (array[mid].endDay < day) {
      low = mid + 1;
    } else {
      high = mid;
    }
  }
  if (array[high].endDay >= day) return array[high].value;
  else return -1; // for day out of range
}

