// Helper functions for time-based throttling
async function shouldSendNewUserEvent(userId) {
  const redisKey = `new_crm_event_sent_${userId}`;
  const lastSentTime = await redisService.getObj(redisKey);

  if (!lastSentTime) {
    return true; // Never sent before
  }

  const timeDiff = Date.now() - parseInt(lastSentTime);
  const twentyFourHours = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

  return timeDiff > twentyFourHours; // Only send if more than 24 hours ago
}

