const _parseAuthenticationHeader = req => {
  let username, password;

  const authorization = req.get(authorizationHeader);
  if (authorization && authorization.indexOf('Basic ') === 0) {
    [username, password] = Buffer.from(authorization.substr(5), 'base64')
      .toString('ascii')
      .split(':');
  }
  if (username && password) {
    return { username, password };
  }
};

