//also checks for valid values
const customValidationBasedOnConfig = (value, helpers, key = null, customCondition = false) => {

  if (customCondition && value === undefined) {
    return helpers.error('any.required'); 
  }
  if (!customCondition && value !== undefined) {
    return helpers.error('any.unknown');
  }
  //if the key is present and required - check for valid values
  if(common_product_validations[key]['validValues'] && !common_product_validations[key]['validValues'].includes(value)){
    return helpers.error('any.invalid');
  }
  return value; 

};

