const logger = require(`@utils/logger`);

// Helper function to calculate totals
function calculateTotals(transactions) {
    logger.info('calculateTotals: Calculating total disbursements and settlements');

    const totals = transactions.reduce((acc, transaction) => {
        acc.totalDisbursements += transaction.disbursements;
        acc.totalSettlements += transaction.settlements;
        return acc;
    }, {
        totalDisbursements: 0,
        totalSettlements: 0
    });

    totals.totalDisbursements = Math.round(totals.totalDisbursements * 100) / 100;
    totals.totalSettlements = Math.round(totals.totalSettlements * 100) / 100;

    return totals;
}

